import { Link, useLocation } from "react-router-dom";

export default function Sidebar() {
  const location = useLocation();

  const menu = [
    { name: "Dashboard", path: "/dashboard" },
    { name: "Project Details", path: "/projects" },
    { name: "Client Management", path: "/clients" },
    { name: "Worker Management", path: "/workers" },
    { name: "Attendance Management", path: "/attendance" },
    { name: "Material Management", path: "/materials" },
  ];

  return (
    <div className="w-64 min-h-screen bg-gradient-to-b from-[#0c2344] to-[#071a33] text-white p-6">
      <div className="mb-12">
        <h2 className="text-xl font-bold text-yellow-400">
          RAJ ENTERPRISES
        </h2>
        <p className="text-xs text-gray-400">
          Builders & Developers
        </p>
      </div>

      <ul className="space-y-4">
        {menu.map((item) => (
          <li key={item.path}>
            <Link
              to={item.path}
              className={`block px-4 py-3 rounded-xl transition ${
                location.pathname === item.path
                  ? "bg-orange-500 text-white"
                  : "hover:bg-white/10 text-gray-300"
              }`}
            >
              {item.name}
            </Link>
          </li>
        ))}
      </ul>
    </div>
  );
}
